import{_ as t,o as a,c as d,a0 as o}from"./chunks/framework.C43iKuuU.js";const h=JSON.parse('{"title":"Packages","description":"","frontmatter":{},"headers":[],"relativePath":"packages.md","filePath":"packages.md"}'),r={name:"packages.md"};function c(i,e,s,n,p,l){return a(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="packages" tabindex="-1">Packages <a class="header-anchor" href="#packages" aria-label="Permalink to &quot;Packages&quot;">​</a></h1><p>Adaptive MCP publishes its core libraries under the <a href="https://www.npmjs.com/org/adaptivemcp" target="_blank" rel="noreferrer"><code>@adaptivemcp</code> npm organization</a>. The packages are dependency-light and follow the same boundaries as the <a href="/guide/architecture.html">architecture</a>.</p><blockquote><p><strong>Version note.</strong> Versions below reflect the current state of the repository (<code>main</code>). Published versions on npm may lag behind; always check the badge for the live published version. The four executor packages are <strong>private</strong> and are not published to npm.</p></blockquote><h2 id="published-adaptivemcp" tabindex="-1">Published (<code>@adaptivemcp/*</code>) <a class="header-anchor" href="#published-adaptivemcp" aria-label="Permalink to &quot;Published (`@adaptivemcp/*`)&quot;">​</a></h2><p>These five are the <strong>published</strong> set (see <code>PUBLISHABLE_PACKAGES</code> in <a href="https://github.com/kemalelmizan/adaptive-mcp/blob/main/scripts/lib/workspace.ts" target="_blank" rel="noreferrer"><code>scripts/lib/workspace.ts</code></a>), released with the <a href="https://github.com/kemalelmizan/adaptive-mcp/blob/main/scripts/release.ts" target="_blank" rel="noreferrer"><code>scripts/release.ts</code></a> flow (see <a href="https://github.com/kemalelmizan/adaptive-mcp/blob/main/docs/RELEASE.md" target="_blank" rel="noreferrer"><code>docs/RELEASE.md</code></a> for the full release runbook).</p><table tabindex="0"><thead><tr><th>Package</th><th>Version</th><th>Install</th><th>Description</th></tr></thead><tbody><tr><td><code>@adaptivemcp/spec</code></td><td><a href="https://www.npmjs.com/package/@adaptivemcp/spec" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/@adaptivemcp/spec" alt="npm"></a> <code>0.1.1</code></td><td><code>npm i @adaptivemcp/spec</code></td><td>Extension identifiers (<code>dev.adaptivemcp/</code> reversed-domain namespace), event schemas, and shared types.</td></tr><tr><td><code>@adaptivemcp/memory</code></td><td><a href="https://www.npmjs.com/package/@adaptivemcp/memory" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/@adaptivemcp/memory" alt="npm"></a> <code>0.2.1</code></td><td><code>npm i @adaptivemcp/memory</code></td><td>Persistent operational knowledge backed by SQLite (<code>node:sqlite</code>), the SSOT.</td></tr><tr><td><code>@adaptivemcp/telemetry</code></td><td><a href="https://www.npmjs.com/package/@adaptivemcp/telemetry" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/@adaptivemcp/telemetry" alt="npm"></a> <code>0.1.1</code></td><td><code>npm i @adaptivemcp/telemetry</code></td><td>Tool execution events and observability (recorder + memory-backed store).</td></tr><tr><td><code>@adaptivemcp/evaluation</code></td><td><a href="https://www.npmjs.com/package/@adaptivemcp/evaluation" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/@adaptivemcp/evaluation" alt="npm"></a> <code>0.2.1</code></td><td><code>npm i @adaptivemcp/evaluation</code></td><td>Outcome scoring and feedback loops; emits <code>observed_failure_rate</code> / <code>avg_duration_ms</code> insights.</td></tr><tr><td><code>@adaptivemcp/extension</code></td><td><a href="https://www.npmjs.com/package/@adaptivemcp/extension" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/@adaptivemcp/extension" alt="npm"></a> <code>0.2.1</code></td><td><code>npm i @adaptivemcp/extension</code></td><td>Derives the YAML <code>tools-metadata</code> view from the SSOT and serves it as the <code>dev.adaptivemcp/tools-metadata</code> MCP resource.</td></tr></tbody></table><h2 id="private-not-published" tabindex="-1">Private (not published) <a class="header-anchor" href="#private-not-published" aria-label="Permalink to &quot;Private (not published)&quot;">​</a></h2><p><code>routing</code>, <code>orchestration</code>, <code>approval</code>, and <code>thin-client</code> are implemented but kept private for now. They are the client-side <strong>executor</strong> of the policy the server governs, and their APIs are still stabilizing. <code>examples</code> and <code>apps</code> are runnable demos, not libraries.</p><table tabindex="0"><thead><tr><th>Package</th><th>Version</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>@adaptivemcp/routing</code></td><td><code>0.0.2</code></td><td><code>Router</code>: model selection + budget guardrails.</td></tr><tr><td><code>@adaptivemcp/orchestration</code></td><td><code>0.0.2</code></td><td><code>Orchestrator</code>: retry-policy (<code>workflow</code>) recommendations.</td></tr><tr><td><code>@adaptivemcp/approval</code></td><td><code>0.0.2</code></td><td><code>ApprovalGate</code>: enforcement (allow / deny / require_confirmation).</td></tr><tr><td><code>@adaptivemcp/thin-client</code></td><td><code>0.0.2</code></td><td><code>ThinClient</code>: client-side execution loop with gate + retry.</td></tr></tbody></table><h2 id="responsibilities-at-a-glance" tabindex="-1">Responsibilities at a glance <a class="header-anchor" href="#responsibilities-at-a-glance" aria-label="Permalink to &quot;Responsibilities at a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>@adaptivemcp/spec</code></td><td>Extension identifiers (<code>dev.adaptivemcp/</code> reversed-domain namespace), event schemas, shared types</td></tr><tr><td><code>@adaptivemcp/memory</code></td><td>SQLite SSOT store (<code>MemoryStore</code>) over <code>node:sqlite</code></td></tr><tr><td><code>@adaptivemcp/telemetry</code></td><td><code>TelemetryRecorder</code> + memory-backed store + stat queries</td></tr><tr><td><code>@adaptivemcp/evaluation</code></td><td><code>Evaluator</code> emits <code>observed_failure_rate</code> / <code>avg_duration_ms</code> insights</td></tr><tr><td><code>@adaptivemcp/extension</code></td><td><code>ExtensionController</code> derives + writes the YAML view and exposes the MCP resource</td></tr><tr><td><code>@adaptivemcp/routing</code></td><td><code>Router</code>: model selection + budget guardrails</td></tr><tr><td><code>@adaptivemcp/orchestration</code></td><td><code>Orchestrator</code>: retry-policy (<code>workflow</code>) recommendations</td></tr><tr><td><code>@adaptivemcp/approval</code></td><td><code>ApprovalGate</code>: enforcement (allow / deny / require_confirmation)</td></tr><tr><td><code>@adaptivemcp/thin-client</code></td><td><code>ThinClient</code>: client-side execution loop with gate + retry</td></tr></tbody></table><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li>Promote <code>routing</code>, <code>orchestration</code>, <code>approval</code>, and <code>thin-client</code> to published packages once their APIs settle.</li><li>Multi-server aggregation: merge <code>tools-metadata</code> across servers into one view.</li><li>More insight types: cost drift, latency regression, and approval friction.</li></ul>',13)])])}const v=t(r,[["render",c]]);export{h as __pageData,v as default};
